// book.schema.ts — CORRECT Mongoose NestJS pattern
import { Prop, Schema, SchemaFactory } from '@nestjs/mongoose';
import { HydratedDocument } from 'mongoose';  // HydratedDocument, NOT Document

export type BookDocument = HydratedDocument<Book>;  // NOT Book & Document

@Schema({ timestamps: true })
export class Book {  // MUST have export keyword
  @Prop({ required: true }) title!: string;   // required → ! (non-null assertion)
  @Prop({ required: true }) author!: string;  // required → !
  @Prop() description?: string;               // optional → ?
  @Prop({ default: true }) isActive?: boolean; // optional with default → ?
}
export const BookSchema = SchemaFactory.createForClass(Book);
// RULES: 1) export class 2) HydratedDocument not Document 3) required=! optional=?

qa:mongoose-required-bang.content:
@Prop({required:true}) → field!: string  (! = required, NON-NULL ASSERTION)
@Prop() → field?: string  (? = optional)
NEVER: @Prop({required:true}) field?: string  (WRONG)
NEVER: @Prop({required:true}) field: string   (WRONG, needs !)
RULE: required=! | optional=? | NO EXCEPTIONS

qa:mongoose-forFeature.content:
NestJS Mongoose module uses MongooseModule.forFeature NEVER TypeOrmModule.
@Module({ imports: [MongooseModule.forFeature([{name: Book.name, schema: BookSchema}])] })
WRONG: TypeOrmModule.forFeature([Book])  ← TypeORM only

